<style>
  :root{
    --bg0:#140b06; --bg1:#241307; --bg2:#3a1d0a;
    --orange:#ff7a18; --orange2:#ffb347; --ink:#1a0e05;
    --panel:rgba(28,16,8,.72); --panelbd:rgba(255,140,40,.35);
    --txt:#ffe9d2; --muted:#c99b73;
  }
  *{box-sizing:border-box; -webkit-tap-highlight-color:transparent;}
  html,body{margin:0;height:100%;overflow:hidden;}
  body{
    font-family:"Segoe UI",system-ui,Arial,sans-serif;
    color:var(--txt);
    background:
      radial-gradient(900px 600px at 50% -10%, rgba(255,122,24,.18), transparent 60%),
      radial-gradient(700px 500px at 90% 110%, rgba(255,80,20,.12), transparent 60%),
      linear-gradient(160deg,var(--bg0),var(--bg1) 45%,var(--bg2));
    height:100%;
    display:flex;align-items:center;justify-content:center;
    overflow:hidden;
    user-select:none;
  }
  #stage{
    display:flex;gap:18px;align-items:flex-start;
    padding:14px;
    max-width:100%;
  }
  .col{display:flex;flex-direction:column;gap:14px;}
  .panel{
    background:var(--panel);
    border:1px solid var(--panelbd);
    border-radius:16px;
    padding:12px 14px;
    box-shadow:0 10px 40px rgba(0,0,0,.5), inset 0 1px 0 rgba(255,255,255,.05);
    backdrop-filter:blur(6px);
  }
  .panel h3{
    margin:0 0 8px;font-size:12px;letter-spacing:2px;text-transform:uppercase;
    color:var(--orange2);font-weight:700;
  }
  #boardWrap{position:relative;}
  canvas{display:block;border-radius:12px;}
  #board{
    background:linear-gradient(180deg,#0d0703,#16100a);
    border:2px solid var(--panelbd);
    box-shadow:0 16px 60px rgba(0,0,0,.6), inset 0 0 60px rgba(0,0,0,.5);
  }
  .mini{background:rgba(10,6,3,.5);border-radius:10px;}
  .stat{display:flex;justify-content:space-between;align-items:baseline;font-size:14px;margin:3px 0;}
  .stat .v{font-weight:800;font-size:20px;color:#fff;font-variant-numeric:tabular-nums;}
  .stat .v.small{font-size:16px;}
  .brand{display:flex;align-items:center;gap:10px;margin-bottom:2px;}
  .brand .logo{
    font-weight:900;font-style:italic;letter-spacing:.5px;line-height:1;
    font-size:24px;
    background:linear-gradient(180deg,#fff,var(--orange2) 60%,var(--orange));
    -webkit-background-clip:text;background-clip:text;color:transparent;
    text-shadow:0 2px 0 rgba(0,0,0,.25);
  }
  .brand .sub{font-size:11px;letter-spacing:3px;color:var(--muted);text-transform:uppercase;}
  .keys{font-size:11px;line-height:1.7;color:var(--muted);}
  .keys b{color:var(--txt);font-weight:700;}
  kbd{
    background:#2a1809;border:1px solid #5a3414;border-bottom-width:2px;border-radius:5px;
    padding:1px 6px;font-size:11px;color:var(--orange2);font-family:inherit;
  }
  /* overlays */
  .overlay{
    position:absolute;inset:0;display:flex;flex-direction:column;
    align-items:center;justify-content:center;text-align:center;gap:12px;
    background:rgba(10,5,2,.86);backdrop-filter:blur(8px);border-radius:12px;
    padding:18px;z-index:5;
  }
  .overlay.hidden{display:none;}
  .title{
    font-weight:900;font-style:italic;font-size:34px;line-height:.95;
    background:linear-gradient(180deg,#fff,var(--orange2) 55%,var(--orange));
    -webkit-background-clip:text;background-clip:text;color:transparent;
    filter:drop-shadow(0 4px 0 rgba(0,0,0,.3));
  }
  .title small{display:block;font-size:15px;letter-spacing:6px;color:var(--muted);font-style:normal;margin-top:6px;}
  .btn{
    cursor:pointer;border:none;border-radius:12px;padding:14px 28px;
    font-size:17px;font-weight:800;letter-spacing:1px;color:var(--ink);
    background:linear-gradient(180deg,var(--orange2),var(--orange));
    box-shadow:0 6px 0 #a4470c, 0 10px 24px rgba(255,120,20,.4);
    transition:transform .06s, box-shadow .06s;
  }
  .btn:active{transform:translateY(4px);box-shadow:0 2px 0 #a4470c,0 6px 14px rgba(255,120,20,.35);}
  .btn.ghost{
    background:rgba(255,255,255,.06);color:var(--txt);
    box-shadow:0 4px 0 rgba(0,0,0,.4); border:1px solid var(--panelbd);
  }
