  .poses canvas{width:62px;height:62px;filter:drop-shadow(0 5px 8px rgba(0,0,0,.55));}
  .poses img{width:100%;height:54px;object-fit:contain;filter:drop-shadow(0 4px 6px rgba(0,0,0,.5));}
  .big{font-size:28px;font-weight:900;color:#fff;}
  .row{display:flex;gap:10px;flex-wrap:wrap;justify-content:center;}
  .toast{
    position:absolute;left:50%;top:34%;transform:translate(-50%,-50%) scale(1);
    font-weight:900;font-style:italic;font-size:34px;pointer-events:none;
    color:#fff;text-shadow:0 0 18px var(--orange),0 4px 0 rgba(0,0,0,.4);
    opacity:0;z-index:4;white-space:nowrap;
  }
  /* touch controls */
  #touch{display:none;gap:10px;margin-top:6px;}
  #touch .pad{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;width:100%;}
  #touch button{
    border:1px solid var(--panelbd);background:rgba(255,255,255,.06);color:var(--txt);
    border-radius:12px;padding:14px 0;font-size:20px;font-weight:800;
  }
  #touch button:active{background:rgba(255,122,24,.3);}
  #muteBtn{position:absolute;top:10px;right:12px;z-index:6;cursor:pointer;
    background:rgba(0,0,0,.35);border:1px solid var(--panelbd);color:var(--orange2);
    border-radius:10px;width:38px;height:38px;font-size:18px;}
  #board{ touch-action:none; }
  .overlay{ overflow:auto; }
  .overlay > *{ max-width:100%; }
  /* Tastatur-Legende als sauberes 2-Spalten-Raster (Menü + Seitenpanel) */
  .kbdgrid{ display:grid; grid-template-columns:auto 1fr; gap:6px 12px;
    align-items:center; max-width:260px; margin:0 auto; }
  .kbdgrid .kk{ white-space:nowrap; text-align:right; }
  .kbdgrid .lbl{ text-align:left; font-size:12px; color:var(--muted); }
  /* Gesten-Hilfe (nur Mobile sichtbar) */
  .gesture-help{ display:none; }
  #gHint{ display:none; }
  @media (max-width:880px){
    /* Body muss stapeln, sonst stünde die Steuerung NEBEN dem Board */
    body{ flex-direction:column; align-items:center; justify-content:flex-start;
      overflow:auto; padding:6px 0 4px; }
    #stage{ flex-direction:column; align-items:center; gap:6px; padding:4px; width:100%; }
    .col.left{ flex-direction:row; flex-wrap:wrap; justify-content:center;
      align-items:center; gap:8px; width:100%; }
    #brandPanel{ display:none; }          /* Logo/TETRIS-Panel im Spiel sparen */
    .col.right{ display:none; }            /* Vorschau-Spalte aus -> Gesten + großes Board */
    .panel{ padding:6px 12px; }
    .keys{ display:none; }
    /* Hold + Stats als kompakte Kopfleiste */
    #holdPanel{ display:flex; flex-direction:row; align-items:center; gap:8px; padding:6px 10px; }
    #holdPanel h3{ margin:0; }
    #hold{ width:42px!important; height:42px!important; }
    #statsPanel h3{ display:none; }
    #statsPanel{ display:flex; flex-wrap:wrap; justify-content:center; gap:4px 14px; }
    #statsPanel .stat{ flex-direction:column; align-items:center; margin:0; gap:0; }
    #statsPanel .stat span:first-child{ font-size:9px; letter-spacing:1px; color:var(--muted); }
    #statsPanel .stat .v{ font-size:16px; }
    /* Touch-Steuerkreuz weg -> Gestensteuerung auf dem Board */
    #touch{ display:none!important; }
    #gHint{ display:block; font-size:10.5px; line-height:1.4; color:var(--muted);
      text-align:center; max-width:96vw; margin-top:4px; }
    /* Startmenü: Gesten statt Tastatur zeigen */
    .gesture-help{ display:block; }
    .overlay{ padding:16px; }
    .title{ font-size:30px; }
    .poses canvas{ width:52px; height:52px; }
    /* Fußleiste in den Fluss statt fixiert */
    #cfFoot{ position:static; margin-top:6px; padding-bottom:10px; }
  }

  /* ── CrazyFamily-Fußleiste (Bestenliste / zurück zur Fun-Zone) ── */
  #cfFoot{ position:fixed; left:0; right:0; bottom:0; z-index:7;
    display:flex; gap:12px; justify-content:center; align-items:center;
    padding:7px 10px; font-size:11px; color:#8a6346; text-align:center;
    pointer-events:none; }
  #cfFoot button, #cfFoot a{ pointer-events:auto; }
  #boardBtn{ background:none; border:none; font:inherit; font-weight:bold;
    color:#ffb347; cursor:pointer; text-shadow:0 0 8px rgba(255,140,40,.6); }
  #backToFunzone{ color:#B6FF00; text-decoration:none; font-weight:bold;
    text-shadow:0 0 8px rgba(182,255,0,.6); }
  #backToFunzone:hover, #backToFunzone:focus-visible, #boardBtn:hover{ text-decoration:underline; }

  /* ── CrazyFamily Highscore-Overlay (globale Top 10 via highscores.php) ── */
  #cfBoard{ position:fixed; inset:0; z-index:99999; display:flex;
    align-items:center; justify-content:center; background:rgba(6,4,10,.82);
    font-family:"Segoe UI",system-ui,Arial,sans-serif; }
  #cfBoard[hidden]{ display:none; }
  #cfBoard .lb-card{ background:#161b26; border:3px solid #2a2f3a; border-radius:10px;
    padding:18px 20px; width:min(92vw,360px); max-height:86vh; overflow:auto;
    color:#EDEDED; text-align:left;
    box-shadow:0 0 24px rgba(255,62,165,.35),0 12px 40px rgba(0,0,0,.7); }
  #cfBoard h2{ margin:0 0 10px; font-size:15px; letter-spacing:1px; color:#ffd36b; }
  #cfBoard #lbResult{ margin:0 0 10px; font-size:13px; }
  #cfBoard #lbResult strong{ color:#B6FF00; }
  #cfBoard #lbSubmitRow{ display:flex; gap:8px; margin:0 0 12px; }
  #cfBoard #lbNick{ flex:1; min-width:0; background:#0B0E14; border:2px solid #3a4150;
    border-radius:8px; color:#fff; padding:8px 10px; font-size:14px; }
  #cfBoard #lbNick:focus{ outline:none; border-color:#FF3EA5; }
  #cfBoard .lb-btn{ background:#FF3EA5; border:none; border-radius:8px; color:#fff;
    font-weight:bold; font-size:13px; padding:8px 14px; cursor:pointer;
    box-shadow:0 3px 0 #8a1f5c; }
  #cfBoard .lb-btn:active{ transform:translateY(2px); box-shadow:0 1px 0 #8a1f5c; }
  #cfBoard .lb-btn[disabled]{ opacity:.6; cursor:default; }
  #cfBoard .lb-btn--ghost{ background:#3a4150; box-shadow:0 3px 0 #1e2330; }
  #cfBoard #lbList{ list-style:none; margin:0 0 14px; padding:0; font-size:13px; }
  #cfBoard #lbList li{ display:flex; gap:8px; padding:5px 2px;
    border-bottom:1px solid rgba(255,255,255,.07); }
  #cfBoard .lb-rank{ color:#7b8499; width:1.6em; }
  #cfBoard .lb-name{ flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
  #cfBoard .lb-score{ color:#ffd23f; font-variant-numeric:tabular-nums; }
  #cfBoard .lb-empty{ color:#7b8499; padding:6px 2px; }
  #cfBoard .lb-actions{ display:flex; justify-content:flex-end; }
</style>
</head>
