<script>
const PIECE_IMG = {"I": "data:image/png;base64,", "O": "data:image/png;base64,", "T": "data:image/png;base64,", "Z": "data:image/png;base64,", "S": "data:image/png;base64,", "J": "data:image/png;base64,", "L": "data:image/png;base64,"};
//======================= ASSETS =======================
// char: welcher CrazyFamily-Kopf auf diesem Stein klebt (kevin = oranger Hoodie, alex = grauer Hoodie)
const PIECES = {
  // Spawn-Formen passend zur gezeichneten Orientierung der Vorlage (TetrisSteineTransparent.png),
  // damit jeder Charakter beim Spawn AUFRECHT steht und als ganzes Bild korrekt mitrotiert.
  I:{cells:[[2,0],[2,1],[2,2],[2,3]], box:4, color:'#33bfe0', char:'kevin'},
  O:{cells:[[1,0],[2,0],[1,1],[2,1]], box:4, color:'#f2bd2e', char:'kevin'},
  T:{cells:[[0,0],[1,0],[2,0],[1,1]], box:3, color:'#b65fd6', char:'alex'},
  S:{cells:[[1,0],[2,0],[0,1],[1,1]], box:3, color:'#57cf63', char:'kevin'},
  Z:{cells:[[0,0],[1,0],[1,1],[2,1]], box:3, color:'#ec5345', char:'alex'},
  J:{cells:[[1,0],[1,1],[1,2],[0,2]], box:3, color:'#4f7ce0', char:'alex'},
  L:{cells:[[0,0],[0,1],[0,2],[1,2]], box:3, color:'#ef8f2e', char:'kevin'},
};
const TYPES = ['I','O','T','S','Z','J','L'];
// Pro Stein EIN zusammenhängendes Bild (aus TetrisSteineTransparent.png), in Spawn-Orientierung.
// Es rotiert als Ganzes mit dem Stein mit (siehe buildPT).
const TILE = {};
for(const t of TYPES){ const im=new Image(); im.src=PIECE_IMG[t]; TILE[t]=im; }
// vorgerenderte Stein-Kacheln: PT[`${t}_${R}`] = Canvas des ganzen Steins (Blöcke + Pose) in Rotation R
const PT = {}; const C = 96;  // Pixel pro Zelle in der Kachel
// Hi-DPI für gestochen scharfe Köpfe
let DPR = Math.max(1, Math.min(2.5, window.devicePixelRatio||1));
const NEXT_W=132, NEXT_H=360, HOLD_W=132, HOLD_H=132;

//======================= CONFIG =======================
const COLS=10, ROWS=20, HIDDEN=2, TOT=ROWS+HIDDEN;
let CELL=30;
const board = document.getElementById('board');
const bctx = board.getContext('2d');
const nextC = document.getElementById('next'), nctx = nextC.getContext('2d');
const holdC = document.getElementById('hold'), hctx = holdC.getContext('2d');

//======================= STATE =======================
let grid, cur, nextQueue, bag, holdType, holdLocked, dropTimer, dropInterval,
    lockTimer, lockResets, score, lines, level, combo, b2b, running, paused,
    over, lastTime, clearing, clearRows, clearAnim, gameStarted=false;

const BEST_KEY='cf_tetris_best';
let best = parseInt(localStorage.getItem(BEST_KEY)||'0',10);

//======================= ROTATION (SRS) =======================
function rotateCells(type, rot){
  const p=PIECES[type], n=p.box-1;
  let cells=p.cells.map(c=>c.slice());
  for(let r=0;r<rot;r++) cells=cells.map(([x,y])=>[n-y,x]);
  return cells;
}
// SRS kick tables (x,y) y-up
const KICK = {
  std:{ '01':[[0,0],[-1,0],[-1,1],[0,-2],[-1,-2]], '10':[[0,0],[1,0],[1,-1],[0,2],[1,2]],
        '12':[[0,0],[1,0],[1,-1],[0,2],[1,2]],     '21':[[0,0],[-1,0],[-1,1],[0,-2],[-1,-2]],
        '23':[[0,0],[1,0],[1,1],[0,-2],[1,-2]],     '32':[[0,0],[-1,0],[-1,-1],[0,2],[-1,2]],
        '30':[[0,0],[-1,0],[-1,-1],[0,2],[-1,2]],   '03':[[0,0],[1,0],[1,1],[0,-2],[1,-2]] },
  I:{   '01':[[0,0],[-2,0],[1,0],[-2,-1],[1,2]],    '10':[[0,0],[2,0],[-1,0],[2,1],[-1,-2]],
        '12':[[0,0],[-1,0],[2,0],[-1,2],[2,-1]],    '21':[[0,0],[1,0],[-2,0],[1,-2],[-2,1]],
        '23':[[0,0],[2,0],[-1,0],[2,1],[-1,-2]],    '32':[[0,0],[-2,0],[1,0],[-2,-1],[1,2]],
        '30':[[0,0],[1,0],[-2,0],[1,-2],[-2,1]],    '03':[[0,0],[-1,0],[2,0],[-1,2],[2,-1]] }
};

//======================= AUDIO =======================
let audioCtx=null, muted=false;
function beep(freq,dur=.07,type='square',vol=.18){
  if(muted) return;
  try{
    audioCtx = audioCtx || new (window.AudioContext||window.webkitAudioContext)();
    const o=audioCtx.createOscillator(), g=audioCtx.createGain();
    o.type=type; o.frequency.value=freq;
    g.gain.setValueAtTime(vol,audioCtx.currentTime);
    g.gain.exponentialRampToValueAtTime(.0001,audioCtx.currentTime+dur);
    o.connect(g); g.connect(audioCtx.destination);
    o.start(); o.stop(audioCtx.currentTime+dur);
  }catch(e){}
}
const sfx={
  move:()=>beep(220,.04,'square',.08),
  rotate:()=>beep(360,.05,'square',.10),
  lock:()=>beep(150,.07,'sawtooth',.12),
  drop:()=>beep(110,.10,'sawtooth',.14),
  clear:(n)=>{ [440,560,700,880].slice(0,n).forEach((f,i)=>setTimeout(()=>beep(f,.12,'triangle',.16),i*60)); },
  level:()=>{ [523,659,784,1046].forEach((f,i)=>setTimeout(()=>beep(f,.12,'triangle',.16),i*80)); },
  hold:()=>beep(300,.05,'sine',.10),
  over:()=>{ [400,330,260,180].forEach((f,i)=>setTimeout(()=>beep(f,.22,'sawtooth',.16),i*150)); }
};

//======================= BAG / SPAWN =======================
function refillBag(){ const b=TYPES.slice(); for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];} bag.push(...b); }
function nextType(){ if(bag.length<=7) refillBag(); return bag.shift(); }
function newPiece(type){
  const box=PIECES[type].box;
  const col=Math.floor((COLS-box)/2);
  return {type, rot:0, x:col, y:0};
}
function spawn(){
  const t = nextQueue.shift(); nextQueue.push(nextType());
  cur = newPiece(t);
  holdLocked=false;
  if(collides(cur.x,cur.y,cur.rot)){ gameOver(); }
  resetLock();
}

//======================= COLLISION =======================
function cellsOf(p){ return rotateCells(p.type,p.rot).map(([x,y])=>[p.x+x,p.y+y]); }
function collides(x,y,rot){
  for(const [cx,cy] of rotateCells(cur.type,rot)){
    const gx=x+cx, gy=y+cy;
    if(gx<0||gx>=COLS||gy>=ROWS) return true;
    if(gy>=0 && grid[gy][gx]) return true;
  }
  return false;
}

//======================= MOVEMENT =======================
function move(dx){ if(!collides(cur.x+dx,cur.y,cur.rot)){ cur.x+=dx; sfx.move(); softResetLock(); draw(); } }
function rotate(dir){
  const from=cur.rot, to=(cur.rot+(dir>0?1:3))%4;
  const table = (cur.type==='I')?KICK.I : (cur.type==='O'?null:KICK.std);
  if(cur.type==='O'){ return; }
  const kicks = table[`${from}${to}`]||[[0,0]];
  for(const [kx,ky] of kicks){
    const nx=cur.x+kx, ny=cur.y-ky;
    if(!collides(nx,ny,to)){ cur.x=nx; cur.y=ny; cur.rot=to; sfx.rotate(); softResetLock(); draw(); return; }
  }
}
function softDrop(){
  if(!collides(cur.x,cur.y+1,cur.rot)){ cur.y++; score+=1; updateHUD(); draw(); resetLock(); }
  else { lockSoon(); }
}
function hardDrop(){
  let d=0;
  while(!collides(cur.x,cur.y+1,cur.rot)){ cur.y++; d++; }
  score+=d*2; sfx.drop(); lockPiece();
}
function ghostY(){ let y=cur.y; while(!collides(cur.x,y+1,cur.rot)) y++; return y; }

//======================= LOCK =======================
function resetLock(){ lockTimer=0; lockResets=0; }
function softResetLock(){ if(lockResets<15 && lockTimer>0){ lockTimer=0; lockResets++; } }
function lockSoon(){ if(lockTimer===0) lockTimer=0.0001; }

function lockPiece(){
  const cells=rotateCells(cur.type,cur.rot);
  let minx=99,miny=99; for(const [x,y] of cells){ minx=Math.min(minx,x); miny=Math.min(miny,y); }
  const w=PIECES[cur.type].box, h=PIECES[cur.type].box;
  // bbox of THIS orientation for image mapping
  let mnx=99,mny=99,mxx=-99,mxy=-99;
  for(const [x,y] of cells){ mnx=Math.min(mnx,x);mny=Math.min(mny,y);mxx=Math.max(mxx,x);mxy=Math.max(mxy,y); }
  for(const [x,y] of cells){
    const gx=cur.x+x, gy=cur.y+y;
    if(gy<0){ gameOver(); return; }
    grid[gy][gx]={t:cur.type, R:cur.rot, cx:x-mnx, cy:y-mny};
  }
  sfx.lock();
  checkLines();
}

//======================= LINE CLEAR =======================
function checkLines(){
  clearRows=[];
  for(let y=0;y<ROWS;y++){ if(grid[y].every(c=>c)) clearRows.push(y); }
  if(clearRows.length){
    clearing=true; clearAnim=0; sfx.clear(clearRows.length);
  }else{
    afterClear(0);
  }
}
function finalizeClear(){
  const n=clearRows.length;
  for(const y of clearRows){ grid.splice(y,1); grid.unshift(new Array(COLS).fill(0)); }
  // scoring
  const base=[0,100,300,500,800][n];
  let pts=base*level;
  const isTetris=(n===4);
  if(isTetris && b2b){ pts=Math.floor(pts*1.5); }
  b2b = isTetris ? true : (n>0?false:b2b);
  if(n>0){ combo++; if(combo>1) pts+=50*combo*level; } else combo=-1;
  score+=pts;
  lines+=n;
  const newLevel=Math.floor(lines/10)+1;
  if(newLevel>level){ level=newLevel; sfx.level(); flash('LEVEL '+level,'#7fe9ff'); }
  setInterval0();
  // toast
  if(n===4) flash('TETRIS!','#ff7a18');
  else if(n===3) flash('TRIPLE','#ffb347');
  else if(n===2) flash('DOUBLE','#ffd27a');
  if(combo>1) flash('COMBO x'+combo,'#a8f5af', n>=3?260:140);
  clearing=false; clearRows=[];
  afterClear(n);
}
function afterClear(n){ spawn(); updateHUD(); draw(); }

function setInterval0(){
  dropInterval = Math.max(40, Math.pow(0.8-((level-1)*0.007),(level-1))*1000);
}

//======================= HOLD =======================
function hold(){
  if(holdLocked) return;
  sfx.hold();
  if(holdType==null){ holdType=cur.type; spawn(); }
  else{ const t=holdType; holdType=cur.type; cur=newPiece(t); if(collides(cur.x,cur.y,cur.rot)) gameOver(); }
  holdLocked=true; resetLock(); draw();
}

//======================= DRAW =======================
function roundRect(ctx,x,y,w,h,r){ ctx.beginPath(); ctx.moveTo(x+r,y); ctx.arcTo(x+w,y,x+w,y+h,r); ctx.arcTo(x+w,y+h,x,y+h,r); ctx.arcTo(x,y+h,x,y,r); ctx.arcTo(x,y,x+w,y,r); ctx.closePath(); }

// normalisierte Zellen (auf 0,0 verschoben) + Bounding-Box für Typ t in Rotation R
function normCells(t,R){
  const cells=rotateCells(t,R);
  let mnx=99,mny=99,mxx=-99,mxy=-99;
  for(const [x,y] of cells){ mnx=Math.min(mnx,x);mny=Math.min(mny,y);mxx=Math.max(mxx,x);mxy=Math.max(mxy,y); }
  return {cells:cells.map(([x,y])=>[x-mnx,y-mny]), bw:mxx-mnx+1, bh:mxy-mny+1};
}
// Stein-Kachel für (t,R) bauen: EIN zusammenhängendes Stein-Bild, als Ganzes in Rotation R
// gedreht (dreht mit dem Stein mit), auf die tatsächlich gefüllten Kollisionszellen geclippt.
// Die orangen Rahmen sind im Bild (TetrisSteineTransparent.png) bereits enthalten.
function buildPT(t,R){
  const p=PIECES[t];
  const n0=normCells(t,0), nR=normCells(t,R);
  const cv=document.createElement('canvas'); cv.width=nR.bw*C; cv.height=nR.bh*C;
  const g=cv.getContext('2d');
  const img=TILE[t];
  g.save();
  g.beginPath();
  for(const [x,y] of nR.cells) g.rect(x*C, y*C, C, C);   // saubere Form (S-Überhang wird abgeschnitten)
  g.clip();
  if(img && img.complete && img.naturalWidth){
    g.translate(cv.width/2, cv.height/2);
    g.rotate(R*Math.PI/2);                                // 90°-CW-Schritte: Bild dreht mit
    g.drawImage(img, -n0.bw*C/2, -n0.bh*C/2, n0.bw*C, n0.bh*C);
  } else {                                                // Fallback bis Bild geladen ist
    g.fillStyle=p.color;
    for(const [x,y] of nR.cells) g.fillRect(x*C+2, y*C+2, C-4, C-4);
  }
  g.restore();
  return cv;
}
function getPT(t,R){ const k=t+'_'+R; return PT[k] || (PT[k]=buildPT(t,R)); }
// eine gelockte Zelle: passenden Ausschnitt aus der Stein-Kachel blitten
function drawCell(ctx, px, py, size, info, opts={}){
  const tile=getPT(info.t, info.R||0); if(!tile) return;
  const a=opts.alpha!=null?opts.alpha:1;
  const cx=info.cx||0, cy=info.cy||0;
  if(a!==1){ ctx.save(); ctx.globalAlpha=a; ctx.drawImage(tile,cx*C,cy*C,C,C,px,py,size,size); ctx.restore(); }
  else ctx.drawImage(tile,cx*C,cy*C,C,C,px,py,size,size);
}
// ganzen aktiven Stein als eine Kachel blitten (an der Bounding-Box)
function drawPieceTile(ctx, t, R, originX, originY, cell){
  const n=normCells(t,R), tile=getPT(t,R);
  ctx.drawImage(tile, originX, originY, n.bw*cell, n.bh*cell);
}
function draw(){
  bctx.setTransform(DPR,0,0,DPR,0,0);
  bctx.clearRect(0,0,COLS*CELL,ROWS*CELL);
  // grid lines
  bctx.strokeStyle='rgba(255,160,80,.06)'; bctx.lineWidth=1;
  for(let x=0;x<=COLS;x++){ bctx.beginPath(); bctx.moveTo(x*CELL,0); bctx.lineTo(x*CELL,ROWS*CELL); bctx.stroke(); }
  for(let y=0;y<=ROWS;y++){ bctx.beginPath(); bctx.moveTo(0,y*CELL); bctx.lineTo(COLS*CELL,y*CELL); bctx.stroke(); }
  // locked
  for(let y=0;y<ROWS;y++) for(let x=0;x<COLS;x++){
    if(grid[y][x]){
      let alpha=1;
      if(clearing && clearRows.includes(y)){
        alpha = 0.5+0.5*Math.cos(clearAnim*22);
      }
      drawCell(bctx, x*CELL, y*CELL, CELL, grid[y][x], {alpha});
    }
  }
  if(clearing) return;
  if(!cur) return;
  // ghost
  const gy=ghostY();
  const cells=rotateCells(cur.type,cur.rot);
  let mnx=99,mny=99,mxx=-99,mxy=-99;
  for(const [x,y] of cells){ mnx=Math.min(mnx,x);mny=Math.min(mny,y);mxx=Math.max(mxx,x);mxy=Math.max(mxy,y); }
  const bw=mxx-mnx+1, bh=mxy-mny+1;
  for(const [x,y] of cells){
    const px=(cur.x+x)*CELL, py=(gy+y)*CELL;
    bctx.save(); bctx.globalAlpha=.18;
    bctx.fillStyle=PIECES[cur.type].color;
    roundRect(bctx,px+3,py+3,CELL-6,CELL-6,5); bctx.fill();
    bctx.restore();
  }
  // active: ganzen Stein als eine Pose-Kachel
  drawPieceTile(bctx, cur.type, cur.rot, (cur.x+mnx)*CELL, (cur.y+mny)*CELL, CELL);
}

// einen Stein zentriert in eine Box (x,y,w,h) einpassen (behält Seitenverhältnis)
function drawPreviewFit(ctx, type, x, y, w, h){
  const n=normCells(type,0), sc=Math.min(w/n.bw, h/n.bh);
  const dw=n.bw*sc, dh=n.bh*sc;
  ctx.drawImage(getPT(type,0), x+(w-dw)/2, y+(h-dh)/2, dw, dh);
}
function drawNext(){
  nctx.setTransform(DPR,0,0,DPR,0,0);
  nctx.clearRect(0,0,NEXT_W,NEXT_H);
  const N=5, slotH=NEXT_H/N, padX=14, padY=12;
  nextQueue.slice(0,N).forEach((t,i)=>
    drawPreviewFit(nctx, t, padX, i*slotH+padY/2, NEXT_W-2*padX, slotH-padY));
}
function drawHold(){
  hctx.setTransform(DPR,0,0,DPR,0,0);
  hctx.clearRect(0,0,HOLD_W,HOLD_H);
  if(holdType){ hctx.globalAlpha=holdLocked?0.45:1;
    drawPreviewFit(hctx, holdType, 18, 18, HOLD_W-36, HOLD_H-36); hctx.globalAlpha=1; }
}

//======================= HUD / TOAST =======================
function updateHUD(){
  document.getElementById('score').textContent=score.toLocaleString('de-DE');
  document.getElementById('lines').textContent=lines;
  document.getElementById('level').textContent=level;
  document.getElementById('best').textContent=best.toLocaleString('de-DE');
  drawNext(); drawHold();
}
const toast=document.getElementById('toast');
let toastT=null;
function flash(text,color,size){
  toast.textContent=text; toast.style.color='#fff';
  toast.style.textShadow=`0 0 18px ${color},0 4px 0 rgba(0,0,0,.4)`;
  if(size) toast.style.fontSize=size+'px'; else toast.style.fontSize='34px';
  toast.style.transition='none'; toast.style.opacity='1';
  toast.style.transform='translate(-50%,-50%) scale(1.25)';
  requestAnimationFrame(()=>{ toast.style.transition='all .6s ease-out';
    toast.style.opacity='0'; toast.style.transform='translate(-50%,-90%) scale(1)'; });
}

//======================= LOOP =======================
function loop(t){
  if(!running){ return; }
  const dt=Math.min(0.05,(t-lastTime)/1000); lastTime=t;
  if(!paused && !over){
    if(clearing){
      clearAnim+=dt;
      if(clearAnim>0.45){ finalizeClear(); }
      draw();
    }else if(cur){
      dropTimer+=dt*1000;
      if(dropTimer>=dropInterval){
        dropTimer=0;
        if(!collides(cur.x,cur.y+1,cur.rot)){ cur.y++; resetLock(); }
        else { lockSoon(); }
      }
      if(lockTimer>0){
        if(collides(cur.x,cur.y+1,cur.rot)){
          lockTimer+=dt;
          if(lockTimer>=0.5){ lockPiece(); }
        } else { lockTimer=0; }
      }
      draw();
    }
  }
  requestAnimationFrame(loop);
}

//======================= GAME FLOW =======================
function resetGame(){
  grid=Array.from({length:ROWS},()=>new Array(COLS).fill(0));
  bag=[]; nextQueue=[]; for(let i=0;i<6;i++) nextQueue.push(nextType());
  holdType=null; holdLocked=false;
  score=0; lines=0; level=1; combo=-1; b2b=false;
  dropTimer=0; lockTimer=0; lockResets=0; clearing=false; clearRows=[];
  over=false; paused=false;
  setInterval0();
  spawn(); updateHUD(); draw();
}
function startGame(){
  document.getElementById('menu').classList.add('hidden');
  document.getElementById('over').classList.add('hidden');
  document.getElementById('pause').classList.add('hidden');
  resetGame();
  running=true; gameStarted=true; lastTime=performance.now();
  try{ audioCtx = audioCtx || new (window.AudioContext||window.webkitAudioContext)(); }catch(e){}
  requestAnimationFrame(loop);
}
function gameOver(){
  if(over) return;
  over=true; running=false; sfx.over();
  if(score>best){ best=score; localStorage.setItem(BEST_KEY,best); }
  document.getElementById('finalScore').textContent=score.toLocaleString('de-DE');
  document.getElementById('overMsg').textContent =
     (score>=best && score>0)?'🔥 Neuer Rekord!':('Beste: '+best.toLocaleString('de-DE'));
  document.getElementById('over').classList.remove('hidden');
  updateHUD();
  // Highscore-Bridge: globale Top 10 (siehe Controller am Seitenende)
  window.dispatchEvent(new CustomEvent('cfgame:final',{detail:{score:score}}));
}
function togglePause(){
  if(over||!gameStarted) return;
  paused=!paused;
  document.getElementById('pause').classList.toggle('hidden',!paused);
  if(!paused){ lastTime=performance.now(); }
}

//======================= INPUT =======================
const repeatKeys={};
document.addEventListener('keydown',e=>{
  if(['ArrowLeft','ArrowRight','ArrowDown','ArrowUp',' '].includes(e.key)) e.preventDefault();
  if(!gameStarted){ if(e.key==='Enter'||e.key===' ') startGame(); return; }
  if(e.key==='p'||e.key==='P'||e.key==='Escape'){ togglePause(); return; }
  if(paused||over||clearing) return;
  switch(e.key){
    case 'ArrowLeft': move(-1); break;
    case 'ArrowRight': move(1); break;
    case 'ArrowDown': softDrop(); break;
    case 'ArrowUp': case 'x': case 'X': rotate(1); break;
    case 'y': case 'Y': case 'z': case 'Z': case 'Control': rotate(-1); break;
    case ' ': hardDrop(); break;
    case 'c': case 'C': case 'Shift': hold(); break;
  }
});
// touch
document.querySelectorAll('#touch button').forEach(b=>{
  const act=b.dataset.act;
  let iv=null;
  const fire=()=>{ if(paused||over||clearing||!gameStarted) return;
    if(act==='left')move(-1); else if(act==='right')move(1);
    else if(act==='rotate')rotate(1); else if(act==='soft')softDrop();
    else if(act==='hard')hardDrop(); else if(act==='hold')hold(); };
  b.addEventListener('touchstart',e=>{ e.preventDefault(); fire();
    if(act==='left'||act==='right'||act==='soft'){ iv=setInterval(fire,90); } },{passive:false});
  b.addEventListener('touchend',e=>{ e.preventDefault(); if(iv){clearInterval(iv);iv=null;} },{passive:false});
});

//======================= GESTEN-STEUERUNG (Wischen/Tippen auf dem Board) =======================
// Tippen = Drehen · Wischen ◀▶ = Bewegen (pro Spaltenbreite) · Wischen ▼ = Soft Drop ·
// schnelles Abwärts-Schnipsen = Hard Drop · Wischen ▲ = Halten.
(function(){
  const cvs=document.getElementById('board');
  let sx=0, sy=0, st=0, refX=0, refY=0, movedH=false, movedV=false;
  const playable=()=> gameStarted && !paused && !over && !clearing;
  const stepX=()=> Math.max(20, CELL*0.85);   // px pro Spalten-Schritt
  const stepY=()=> Math.max(22, CELL*0.95);   // px pro Soft-Drop-Schritt

  cvs.addEventListener('touchstart',e=>{
    if(!playable()) return;
    const t=e.touches[0];
    sx=refX=t.clientX; sy=refY=t.clientY; st=performance.now();
    movedH=false; movedV=false;
    e.preventDefault();
  },{passive:false});

  cvs.addEventListener('touchmove',e=>{
    if(!playable()) return;
    const t=e.touches[0];
    let dx=t.clientX-refX, s=stepX();
    while(dx>=s){ move(1);  refX+=s; dx-=s; movedH=true; }
    while(dx<=-s){ move(-1); refX-=s; dx+=s; movedH=true; }
    let dy=t.clientY-refY, v=stepY();
    while(dy>=v){ softDrop(); refY+=v; dy-=v; movedV=true; }
    if(dy<0) refY=t.clientY;   // Aufwärts nicht akkumulieren (Hold kommt bei touchend)
    e.preventDefault();
  },{passive:false});

  cvs.addEventListener('touchend',e=>{
    if(!playable()) return;
    const t=(e.changedTouches&&e.changedTouches[0])||{clientX:sx,clientY:sy};
    const dt=performance.now()-st, dx=t.clientX-sx, dy=t.clientY-sy;
    const adx=Math.abs(dx), ady=Math.abs(dy);
    if(movedH||movedV){
      // war eine Zieh-Geste: schnelles, reines Abwärts-Schnipsen => Hard Drop
      if(!movedH && dy>0 && dt<260 && ady>70) hardDrop();
      return;
    }
    if(adx<14 && ady<14 && dt<260){ rotate(1); return; }   // Tippen = Drehen
    if(ady>adx){
      if(dy>0){ (dt<260 && ady>60) ? hardDrop() : softDrop(); }   // runter
      else hold();                                                // hoch = Halten
    } else {
      move(dx>0?1:-1);                                            // kurze Wischbewegung
    }
  },{passive:false});
})();

//======================= UI WIRING =======================
document.getElementById('startBtn').onclick=startGame;
document.getElementById('restartBtn').onclick=startGame;
document.getElementById('restartBtn2').onclick=startGame;
document.getElementById('resumeBtn').onclick=togglePause;
document.getElementById('muteBtn').onclick=function(){ muted=!muted; this.textContent=muted?'🔇':'🔊'; };

// Steuerungs-Legende (Tastatur) als sauberes 2-Spalten-Raster
const KB_CONTROLS=[
  ['<kbd>◀</kbd><kbd>▶</kbd>','Bewegen'],
  ['<kbd>▲</kbd> <kbd>X</kbd>','Drehen'],
  ['<kbd>Y</kbd> / <kbd>Z</kbd>','Zurück drehen'],
  ['<kbd>▼</kbd>','Soft Drop'],
  ['<kbd>Leer</kbd>','Hard Drop'],
  ['<kbd>C</kbd> <kbd>⇧</kbd>','Halten'],
  ['<kbd>P</kbd> <kbd>Esc</kbd>','Pause'],
];
// Gesten-Legende (Touch) fürs Startmenü auf dem Handy
const GESTURES=[
  ['👆','Tippen = Drehen'],
  ['👈 👉','Wischen = Bewegen'],
  ['👇','Wischen = Runter'],
  ['💨','Runter schnipsen = Hard Drop'],
  ['🔼','Hoch wischen = Halten'],
];
function legendGrid(rows){
  return '<div class="kbdgrid">'+rows.map(r=>
    '<span class="kk">'+r[0]+'</span><span class="lbl">'+r[1]+'</span>').join('')+'</div>';
}
// Tastatur-Legende nur noch im eigenen Seitenpanel (rechts) – nicht mehr im Start-Overlay,
// damit das Menü kompakt bleibt und keinen Scrollbalken bekommt.
document.getElementById('sideKeys').innerHTML='<h3>Steuerung</h3>'+legendGrid(KB_CONTROLS);
document.getElementById('menuGestures').innerHTML='<h3 style="text-align:center">📱 Gesten</h3>'+legendGrid(GESTURES);
// Menü-Showcase: alle 7 Steine als kleine Kacheln in Spawn-Form
function buildMenu(){
  const mp=document.getElementById('menuPoses'); mp.innerHTML='';
  for(const t of TYPES){
    const n=normCells(t,0), sz=44;
    const c=document.createElement('canvas');
    c.width=4*sz; c.height=4*sz;   // Anzeigegröße kommt aus dem CSS (.poses canvas)
    const g=c.getContext('2d');
    const ox=(4*sz-n.bw*sz)/2, oy=(4*sz-n.bh*sz)/2;
    g.drawImage(getPT(t,0), ox, oy, n.bw*sz, n.bh*sz);
    mp.appendChild(c);
  }
}

//======================= RESPONSIVE SIZE =======================
function setupCanvas(c, w, h){
  c.width=Math.round(w*DPR); c.height=Math.round(h*DPR);
  c.style.width=w+'px'; c.style.height=h+'px';
  c.getContext('2d').setTransform(DPR,0,0,DPR,0,0);
}
function fit(){
  const maxW = window.innerWidth;
  const isMobile = maxW <= 880;
  // Auf Mobile Platz für die kompakte Kopfleiste (Hold + Stats) und den Gesten-Hinweis
  // reservieren – das Steuerkreuz entfällt (Gestensteuerung), daher passt alles auf den Schirm.
  const reserveH = isMobile ? 150 : 90;
  const maxH = Math.min(window.innerHeight - reserveH, 1040);
  let cell = Math.floor(maxH/ROWS);
  if(!isMobile){ cell=Math.min(cell, Math.floor((maxW-420)/COLS)); }
  else { cell=Math.min(cell, Math.floor((maxW-24)/COLS)); }
  // Desktop bewusst kompakter deckeln – die Spiele sind klein, alles soll ohne Scroll passen
  const maxCell = isMobile ? 54 : 40;
  cell=Math.max(18,Math.min(maxCell,cell));
  CELL=cell;
  setupCanvas(board, COLS*CELL, ROWS*CELL);
  setupCanvas(nextC, NEXT_W, NEXT_H);
  setupCanvas(holdC, HOLD_W, HOLD_H);
  if(gameStarted){ drawNext(); drawHold(); draw(); }
}
window.addEventListener('resize',fit);

//======================= BOOT =======================
function ready(){ buildMenu(); fit(); }
Promise.all(TYPES.map(t=>new Promise(res=>{ const im=TILE[t]; if(im.complete) res(); else { im.onload=res; im.onerror=res; } })))
  .then(ready);
fit();
</script>

<!-- Bestenlisten-Overlay: erscheint bei Game Over (Event cfgame:final) oder per 🏆-Button.
     Globale Top 10 über die bestehende Highscore-API (assets/api/highscores.php). -->
<div id="cfBoard" hidden>
  <div class="lb-card">
    <h2 id="lbTitle">🏆 Bestenliste</h2>
    <p id="lbResult" hidden>Dein Ergebnis: <strong id="lbScore">0</strong></p>
    <div id="lbSubmitRow" hidden>
      <input type="text" id="lbNick" maxlength="16" placeholder="Dein Name" aria-label="Spitzname für die Bestenliste" />
      <button type="button" id="lbSubmit" class="lb-btn">Eintragen</button>
    </div>
    <ol id="lbList" aria-label="Globale Bestenliste"></ol>
    <div class="lb-actions">
      <button type="button" id="lbClose" class="lb-btn lb-btn--ghost">Schließen</button>
    </div>
  </div>
</div>

<script src="/assets/js/games/arcade.js" defer></script>
<script>
/* Highscore-Controller (globale Top 10 via highscores.php). Läuft nach dem defer-Skript.
   Das Spiel feuert bei Game Over window.dispatchEvent(new CustomEvent('cfgame:final',{detail:{score}})). */
document.addEventListener('DOMContentLoaded', function () {
  if (!window.CFArcade) return;
  var GAME = 'tetris';

  var board     = document.getElementById('cfBoard');
  var title     = document.getElementById('lbTitle');
  var result    = document.getElementById('lbResult');
  var scoreEl   = document.getElementById('lbScore');
  var submitRow = document.getElementById('lbSubmitRow');
  var nick      = document.getElementById('lbNick');
  var submitBtn = document.getElementById('lbSubmit');
  var list      = document.getElementById('lbList');
  var pendingScore = 0;

  // Solange das Overlay offen ist, dürfen die Spieltasten nicht beim Spiel landen
  // -> Capture-Phase stoppt sie vor den Spiel-Listenern.
  ['keydown', 'keyup'].forEach(function (ev) {
    window.addEventListener(ev, function (e) {
      if (board.hidden) return;
      if (e.code === 'Escape' && ev === 'keydown') { e.stopPropagation(); closeBoard(); return; }
      e.stopPropagation();
      if (CFArcade.isTyping(e.target) && e.code === 'Enter' && ev === 'keydown') submit();
    }, true);
  });

  function renderBoard(scores) {
    if (!scores || !scores.length) {
      list.innerHTML = '<li class="lb-empty">Noch keine Einträge – sei der Erste!</li>';
      return;
    }
    list.innerHTML = scores.map(function (s, i) {
      return '<li><span class="lb-rank">' + (i + 1) + '.</span>' +
             '<span class="lb-name">' + s.name + '</span>' +
             '<span class="lb-score">' + s.score + '</span></li>';
    }).join('');
  }
  function refreshBoard() {
    list.innerHTML = '<li class="lb-empty">Lade…</li>';
    CFArcade.loadGlobal(GAME).then(renderBoard);
  }

  function openBoard(mode, score) {
    var over = mode === 'final';
    title.textContent = over ? '🏁 Game Over' : '🏆 Bestenliste';
    result.hidden = !over;
    if (over) {
      var record = CFArcade.setLocalBest(GAME, score);
      scoreEl.textContent = score + (record ? ' 🏆 Neuer Rekord!' : '');
      pendingScore = score;
    }
    submitRow.hidden = !(over && pendingScore > 0);
    submitBtn.disabled = false;
    submitBtn.textContent = 'Eintragen';
    nick.value = CFArcade.getNick();
    board.hidden = false;
    refreshBoard();
  }
  function closeBoard() { board.hidden = true; }

  function submit() {
    if (pendingScore <= 0 || submitBtn.disabled) return;
    var name = (nick.value || '').trim() || 'Anonym';
    CFArcade.setNick(name);
    submitBtn.disabled = true;
    submitBtn.textContent = 'Gesendet ✓';
    CFArcade.submitGlobal(GAME, name, pendingScore).then(renderBoard);
    pendingScore = 0;
    submitRow.hidden = true;
  }

  // Spielende -> Ergebnis-/Eintrag-Overlay (kurz den Game-Over-Sound wirken lassen)
  window.addEventListener('cfgame:final', function (e) {
    setTimeout(function () { openBoard('final', Math.floor(e.detail.score)); }, 900);
  });

  document.getElementById('boardBtn').addEventListener('click', function () {
    board.hidden ? openBoard('view') : closeBoard();
  });
  document.getElementById('lbClose').addEventListener('click', closeBoard);
  submitBtn.addEventListener('click', submit);
});
</script>

</body>
</html>
